CREATE TABLE products (
  product_id INT PRIMARY KEY,
  name       VARCHAR(60),
  price      DECIMAL(8,2)
);

INSERT INTO products VALUES (1,'Laptop',999.99),(2,'Mouse',19.99),(3,'Keyboard',59.99);

-- Default isolation level in PostgreSQL
SHOW transaction_isolation;

-- READ COMMITTED demo: each statement sees latest committed data
-- With READ COMMITTED:
-- Session A: BEGIN; UPDATE price to 899.99 (not yet committed)
-- Session B: SELECT price -- sees 999.99 (Session A not committed yet)
-- Session A: COMMIT
-- Session B: SELECT price again -- now sees 899.99 (correctly reads committed value)

-- Single-session simulation:
SELECT price FROM products WHERE product_id = 1;  -- 999.99

BEGIN;
  UPDATE products SET price = 899.99 WHERE product_id = 1;
  -- Within the same transaction we can see our own change:
  SELECT price FROM products WHERE product_id = 1;  -- 899.99 (our own change)
COMMIT;

-- After COMMIT, all readers see the new price:
SELECT price FROM products WHERE product_id = 1;  -- 899.99

CREATE TABLE account_balances (
  account_id INT PRIMARY KEY,
  owner      VARCHAR(50),
  balance    DECIMAL(10,2)
);

INSERT INTO account_balances VALUES
  (1,'Alice',1000.00),
  (2,'Bob',  800.00),
  (3,'Carol',600.00);

-- Set isolation level to REPEATABLE READ
BEGIN TRANSACTION ISOLATION LEVEL REPEATABLE READ;
  -- First read: see initial total
  SELECT SUM(balance) AS total_balance FROM account_balances;

  -- Imagine another session commits: Alice changes to 1200 here
  -- (In REPEATABLE READ, we would NOT see that change in this transaction)

  -- Second read: same result as first read in REPEATABLE READ
  SELECT SUM(balance) AS total_balance FROM account_balances;

COMMIT;

-- After transaction: a concurrent change would be visible
SELECT SUM(balance) AS current_total FROM account_balances;

-- Isolation level summary table for reference
CREATE TABLE isolation_levels (
  level_name      VARCHAR(30) PRIMARY KEY,
  order_number    INT,
  dirty_read      VARCHAR(10),
  nonrepeatable_read VARCHAR(10),
  phantom_read    VARCHAR(10),
  performance     VARCHAR(10)
);

INSERT INTO isolation_levels VALUES
  ('READ UNCOMMITTED', 1, 'Possible', 'Possible', 'Possible', 'Highest'),
  ('READ COMMITTED',   2, 'Prevented','Possible', 'Possible', 'High'),
  ('REPEATABLE READ',  3, 'Prevented','Prevented','Possible', 'Medium'),
  ('SERIALIZABLE',     4, 'Prevented','Prevented','Prevented','Lowest');

-- Query: See all anomaly risks per isolation level
SELECT level_name, dirty_read, nonrepeatable_read, phantom_read, performance
FROM isolation_levels
ORDER BY order_number;

-- Demonstrate SERIALIZABLE transaction (strictest)
BEGIN TRANSACTION ISOLATION LEVEL SERIALIZABLE;
  -- Any reads here are guaranteed to be consistent
  SELECT level_name, performance FROM isolation_levels ORDER BY order_number;
COMMIT;

-- Check current session isolation level
SELECT current_setting('transaction_isolation') AS current_isolation;
